"""Process derivation.

A "process" is one *instance* of a Claude Code run, identified by
(pid, source_system, cwd) **and** the time window bounded by
claude_log_pid_deaths rows. PID reuse over time means a single tuple may
correspond to multiple distinct process instances; each gets its own
ProcessResponse with its own process_id, started_at, ended_at, etc.

Instance windowing is encapsulated in `_instance.py`. Every aggregator
helper here filters its rows by `after` (exclusive lower) and `until`
(inclusive upper) bounds.
"""

import aiosqlite

from agentpulse.api.v2.ids import derive_process_id
from agentpulse.api.v2.queries._helpers import (
    active_agent_states,
    agents_for_session,
    latest_hook_for_session,
)
from agentpulse.api.v2.queries._instance import (
    _NO_LOWER,
    _NO_UPPER,
    _instance_windows,
)
from agentpulse.api.v2.queries.sessions import get_session_by_id
from agentpulse.api.v2.state import compute_effective_state, derive_state


def _bounds(after: float | None, until: float | None) -> tuple[float, float]:
    """Translate None-bounds to SQLite-friendly sentinels."""
    return (
        after if after is not None else _NO_LOWER,
        until if until is not None else _NO_UPPER,
    )


async def _process_identity_tuples(
    db: aiosqlite.Connection,
) -> list[tuple[int, str, str]]:
    """Distinct (pid, source_system, cwd) tuples across both log tables."""
    cursor = await db.execute("""
        SELECT pid, source_system, cwd FROM claude_log_hooks
        UNION
        SELECT pid, source_system, cwd FROM claude_log_statuslines
        """)
    rows = await cursor.fetchall()
    return [(r["pid"], r["source_system"], r["cwd"]) for r in rows]


async def _hook_window(
    db: aiosqlite.Connection,
    *,
    pid: int,
    source_system: str,
    cwd: str,
    after: float | None,
    until: float | None,
) -> dict:
    after_v, until_v = _bounds(after, until)
    cursor = await db.execute(
        """
        SELECT MIN(received_at) AS started_at,
               MAX(received_at) AS last_activity_at,
               COUNT(*) AS event_count
        FROM claude_log_hooks
        WHERE pid = ? AND source_system = ? AND cwd = ?
              AND received_at > ? AND received_at <= ?
        """,
        (pid, source_system, cwd, after_v, until_v),
    )
    row = await cursor.fetchone()
    return dict(row) if row else {}


